   301→                  </button>
   302→                )}
   303→              </div>
   304→            )}
   305→          </div>
   306→        </div>
   307→
   308→        {/* Graph or Empty State */}
   309→        {!hasNotes ? (
   310→          <div className="flex-1 flex items-center justify-center">
   311→            <div className="text-center">
   312→              <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2">
   313→                No notes yet
   314→              </p>
   315→              <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary">
   316→                Create some notes with backlinks to see your knowledge graph
