   349→            <div className="flex items-center gap-2">
   350→              <div className="w-3 h-3 rounded-full bg-[var(--accent-magenta)]" />
   351→              <span>Tags</span>
   352→            </div>
   353→            <div className="flex items-center gap-2">
   354→              <div className="w-8 h-0.5 bg-[var(--accent-cyan)]" />
   355→              <span>Backlinks</span>
