   392→      let groupKey: string | undefined;
   393→
   394→      if (colorBy === 'folder') {
   395→        groupKey = node.metadata.folder || 'root';
   396→      } else if (colorBy === 'tag' && node.metadata.tags && node.metadata.tags.length > 0) {
   397→        groupKey = node.metadata.tags[0];
   398→      }
   399→
   400→      if (groupKey) {
   401→        const existing = groups.get(groupKey);
   402→        if (existing) {
   403→          existing.count++;
   404→        } else {
   405→          groups.set(groupKey, { color: node.color, count: 1 });
   406→        }
   407→      }
   408→    }
   409→  });
   410→
   411→  return groups;
   412→}
