 */
export type LinkStrength = 'strong' | 'medium' | 'weak';

/**
 * Search filters for graph nodes
 */
export interface GraphSearchFilters {
  /** Text search query for node titles/content */
  query?: string;
  /** Filter by specific tags */
  tags?: string[];
  /** Filter by node type */
  nodeType?: 'note' | 'tag' | 'both';
