 * Orphan node details
 */
export interface OrphanNode {
  /** Node ID */
  nodeId: string;
  /** Node title */
  title: string;
  /** Suggested connections */
  suggestions: OrphanSuggestion[];
  /** When it was created */
  createdAt: string;
}

