 * Search bar with filters for graph visualization
 */

import { useState, useEffect } from 'react';
import { Search, X, Filter } from 'lucide-react';
import type { GraphSearchFilters } from '../../types/graph';

interface GraphSearchProps {
  /** Available tags for filtering */
  availableTags: string[];
  /** Current filters */
  filters: GraphSearchFilters;
  /** Callback when filters change */
  onFiltersChange: (filters: GraphSearchFilters) => void;
  /** Number of matching results */
  resultCount?: number;
}

export function GraphSearch({
  availableTags,
  filters,
  onFiltersChange,
  resultCount,
}: GraphSearchProps) {
  const [localQuery, setLocalQuery] = useState(filters.query || '');
  const [showAdvanced, setShowAdvanced] = useState(false);

  // Debounce query updates
  useEffect(() => {
    const timeoutId = setTimeout(() => {
      onFiltersChange({ ...filters, query: localQuery });
    }, 300);

    return () => clearTimeout(timeoutId);
  }, [localQuery]);

  const handleClearAll = () => {
    setLocalQuery('');
    onFiltersChange({
      query: undefined,
      tags: undefined,
      nodeType: 'both',
      connectedTo: undefined,
    });
