/**
 * Graph View Page
 * Visual network of notes and their connections
 */

import { useMemo, useState, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { PageHeader } from '../components/PageHeader';
import { GraphCanvas } from '../components/Graph/GraphCanvas';
import { GraphSearch } from '../components/Graph/GraphSearch';
import { OrphanPanel } from '../components/Graph/OrphanPanel';
import { LinkStrengthLegend } from '../components/Graph/LinkStrengthLegend';
import { useNotesStore } from '../stores/useNotesStore';
import { useFoldersStore } from '../stores/useFoldersStore';
import { buildGraphData, type GraphFilters, getUniqueTags, getColorGroups } from '../utils/graphDataProcessor';
import { searchGraphNodes, type SearchResult } from '../utils/graphSearch';
import { getOrphansWithSuggestions, detectOrphans } from '../utils/graphOrphanDetection';
import type { GraphSearchFilters } from '../types/graph';
import { Search, FolderOpen, Tag, Target, X, Palette, AlertCircle, Link2 } from 'lucide-react';

export default function GraphView() {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const notes = useNotesStore((state) => state.notes);
  const updateNote = useNotesStore((state) => state.updateNote);
  const addTag = useNotesStore((state) => state.addTag);
  const folders = useFoldersStore((state) => state.folders);

  const [searchQuery, setSearchQuery] = useState('');
  const [hideOrphans, setHideOrphans] = useState(false);
  const [selectedTags, setSelectedTags] = useState<string[]>([]);
  const [selectedFolders, setSelectedFolders] = useState<string[]>([]);
  const [colorBy, setColorBy] = useState<'none' | 'folder' | 'tag'>('none'); // P1: Color grouping
  const [sizeByConnections, setSizeByConnections] = useState(true); // P1: Node sizing

  // P2: New state for advanced features
  const [showLinkStrength, setShowLinkStrength] = useState(true); // P2: Link strength visualization
  const [graphSearchFilters, setGraphSearchFilters] = useState<GraphSearchFilters>({}); // P2: Graph search
  const [searchResult, setSearchResult] = useState<SearchResult | null>(null); // P2: Search results
  const [showOrphanPanel, setShowOrphanPanel] = useState(false); // P2: Orphan panel

  // Focus mode state
  const [focusNodeId, setFocusNodeId] = useState<string | null>(null);
  const [focusDepth, setFocusDepth] = useState(2); // Default 2 hops

  // Get available tags and folders
  const availableTags = useMemo(() => getUniqueTags(notes), [notes]);
  const availableFolders = useMemo(() => Object.keys(folders), [folders]);

  // Persist visual settings to localStorage
  useEffect(() => {
    localStorage.setItem('graph-visual-settings', JSON.stringify({
      colorBy,
      sizeByConnections,
    }));
  }, [colorBy, sizeByConnections]);

  // Restore visual settings from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('graph-visual-settings');
    if (saved) {
      try {
        const { colorBy: savedColorBy, sizeByConnections: savedSizing } = JSON.parse(saved);
        if (savedColorBy) setColorBy(savedColorBy);
        if (typeof savedSizing === 'boolean') setSizeByConnections(savedSizing);
      } catch (error) {
        // Invalid JSON, ignore
      }
    }
  }, []);

  // URL param support for focus mode
  useEffect(() => {
    const focusParam = searchParams.get('focus');
    if (focusParam && notes[focusParam]) {
      setFocusNodeId(focusParam);
    }
  }, [searchParams, notes]);

  // Persist focus state to localStorage
  useEffect(() => {
    if (focusNodeId) {
      localStorage.setItem('graph-focus', JSON.stringify({ nodeId: focusNodeId, depth: focusDepth }));
    } else {
      localStorage.removeItem('graph-focus');
    }
  }, [focusNodeId, focusDepth]);

  // Restore focus from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('graph-focus');
    if (saved && !searchParams.get('focus')) {
      try {
        const { nodeId, depth } = JSON.parse(saved);
        if (notes[nodeId]) {
          setFocusNodeId(nodeId);
          setFocusDepth(depth);
        } else {
          // Note was deleted, clear saved focus
          localStorage.removeItem('graph-focus');
        }
      } catch (error) {
        localStorage.removeItem('graph-focus');
      }
    }
  }, [notes, searchParams]);

  // Build graph data with filters
  const graphData = useMemo(() => {
    const filters: GraphFilters = {
      searchQuery,
      hideOrphans,
      selectedTags: selectedTags.length > 0 ? selectedTags : undefined,
      selectedFolders: selectedFolders.length > 0 ? selectedFolders : undefined,
      focusNodeId: focusNodeId || undefined,
      focusDepth: focusNodeId ? focusDepth : undefined,
      colorBy, // P1: Color grouping
      sizeByConnections, // P1: Node sizing
    };
    return buildGraphData(notes, filters);
  }, [notes, searchQuery, hideOrphans, selectedTags, selectedFolders, focusNodeId, focusDepth, colorBy, sizeByConnections]);

  // P1: Get color groups for legend
  const colorGroups = useMemo(() => getColorGroups(graphData, colorBy), [graphData, colorBy]);

  // Handle node click - focus on node
  const handleNodeClick = (nodeId: string, nodeType: 'note' | 'tag') => {
    if (nodeType === 'note') {
      setFocusNodeId(nodeId);
      setSearchParams({ focus: nodeId });
    }
  };

  // Handle node double-click - navigate to note
  const handleNodeDoubleClick = (nodeId: string, nodeType: 'note' | 'tag') => {
    if (nodeType === 'note') {
      navigate(`/notes?note=${nodeId}`);
    }
  };

  // Reset focus mode
  const resetFocus = () => {
    setFocusNodeId(null);
    setSearchParams({});
  };

  // Check if empty
  const hasNotes = Object.keys(notes).length > 0;

  return (
    <div className="flex flex-col h-full">
      <PageHeader title="Graph View" />

      <div className="flex-1 flex flex-col p-6 gap-4 overflow-hidden">
        {/* Focus Mode Banner */}
        {focusNodeId && notes[focusNodeId] && (
          <div className="flex items-center gap-4 p-3 bg-gradient-to-r from-accent-cyan/10 to-accent-magenta/10 dark:from-accent-cyan/20 dark:to-accent-magenta/20 rounded-lg border border-accent-cyan/20 dark:border-accent-cyan/30">
            <Target className="w-4 h-4 text-accent-cyan flex-shrink-0" />
            <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
              Focused: {notes[focusNodeId]?.title}
            </span>

            <div className="flex items-center gap-2 ml-auto">
              <label className="flex items-center gap-2">
                <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary whitespace-nowrap">
                  Depth:
                </span>
                <input
                  type="range"
                  min="1"
                  max="3"
                  value={focusDepth}
                  onChange={(e) => setFocusDepth(parseInt(e.target.value))}
                  className="w-20 accent-accent-magenta"
                />
                <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary w-12">
                  {focusDepth} hop{focusDepth > 1 ? 's' : ''}
                </span>
              </label>

              <button
                onClick={resetFocus}
                className="flex items-center gap-1 px-3 py-1.5 text-xs rounded-lg bg-accent-magenta/10 hover:bg-accent-magenta/20 text-accent-magenta transition-colors"
              >
                <X className="w-3 h-3" />
                Reset
              </button>
            </div>
          </div>
        )}

        {/* Controls */}
        <div className="flex flex-col gap-3">
          {/* Row 1: Search and Hide Orphans */}
          <div className="flex items-center gap-4 flex-wrap">
            {/* Search */}
            <div className="relative flex-1 min-w-[200px]">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
              <input
                type="text"
                placeholder="Search notes..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-4 py-2 rounded-lg border border-border-light dark:border-border-dark bg-surface-light-base dark:bg-surface-dark-base text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta"
              />
            </div>

            {/* Hide Orphans Toggle */}
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="checkbox"
                checked={hideOrphans}
                onChange={(e) => setHideOrphans(e.target.checked)}
                className="w-4 h-4 rounded border-border-light dark:border-border-dark text-accent-magenta focus:ring-accent-magenta"
              />
              <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                Hide orphans
              </span>
            </label>

            {/* P1: Color Grouping */}
            <div className="flex items-center gap-2">
              <Palette className="w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
              <select
                value={colorBy}
                onChange={(e) => setColorBy(e.target.value as 'none' | 'folder' | 'tag')}
                className="px-3 py-1.5 text-sm rounded-lg border border-border-light dark:border-border-dark bg-surface-light-base dark:bg-surface-dark-base text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta"
              >
                <option value="none">Default colors</option>
                <option value="folder">Color by folder</option>
                <option value="tag">Color by tag</option>
              </select>
            </div>

            {/* P1: Node Sizing Toggle */}
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="checkbox"
                checked={sizeByConnections}
                onChange={(e) => setSizeByConnections(e.target.checked)}
                className="w-4 h-4 rounded border-border-light dark:border-border-dark text-accent-cyan focus:ring-accent-cyan"
              />
              <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                Size by connections
              </span>
            </label>

            {/* Stats */}
            <div className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary">
              {graphData.nodes.length} nodes · {graphData.edges.length} connections
            </div>
          </div>

          {/* Row 2: Tag and Folder Filters */}
          <div className="flex items-center gap-4 flex-wrap">
            {/* Tag Filter */}
            {availableTags.length > 0 && (
              <div className="flex items-center gap-2">
                <Tag className="w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
                <select
                  multiple
                  value={selectedTags}
                  onChange={(e) => {
                    const options = Array.from(e.target.selectedOptions, option => option.value);
                    setSelectedTags(options);
                  }}
                  className="px-3 py-1.5 text-sm rounded-lg border border-border-light dark:border-border-dark bg-surface-light-base dark:bg-surface-dark-base text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta max-h-10"
                  size={1}
                >
                  <option value="" disabled>Filter by tags...</option>
                  {availableTags.map((tag) => (
                    <option key={tag} value={tag}>
                      {tag}
                    </option>
                  ))}
                </select>
                {selectedTags.length > 0 && (
                  <button
                    onClick={() => setSelectedTags([])}
                    className="px-2 py-1 text-xs rounded bg-accent-magenta/10 text-accent-magenta hover:bg-accent-magenta/20"
                  >
                    Clear ({selectedTags.length})
                  </button>
                )}
              </div>
            )}

            {/* Folder Filter */}
            {availableFolders.length > 0 && (
              <div className="flex items-center gap-2">
                <FolderOpen className="w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
                <select
                  multiple
                  value={selectedFolders}
                  onChange={(e) => {
                    const options = Array.from(e.target.selectedOptions, option => option.value);
                    setSelectedFolders(options);
                  }}
                  className="px-3 py-1.5 text-sm rounded-lg border border-border-light dark:border-border-dark bg-surface-light-base dark:bg-surface-dark-base text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta max-h-10"
                  size={1}
                >
                  <option value="" disabled>Filter by folders...</option>
                  {availableFolders.map((folderId) => (
                    <option key={folderId} value={folderId}>
                      {folders[folderId]?.name || folderId}
                    </option>
                  ))}
                </select>
                {selectedFolders.length > 0 && (
                  <button
                    onClick={() => setSelectedFolders([])}
                    className="px-2 py-1 text-xs rounded bg-accent-cyan/10 text-accent-cyan hover:bg-accent-cyan/20"
                  >
                    Clear ({selectedFolders.length})
                  </button>
                )}
              </div>
            )}
          </div>
        </div>

        {/* Graph or Empty State */}
        {!hasNotes ? (
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center">
              <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2">
                No notes yet
              </p>
