            <div className="flex items-center gap-2">
              <div className="w-3 h-3 rounded-full bg-[var(--accent-magenta)] border-2 border-orange-500" />
              <span>Orphans</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-8 h-0.5 bg-[var(--accent-cyan)]" />
              <span>Backlinks</span>
