        </div>
        </div>

        {/* P2: Orphan Panel (Sidebar) */}
        {showOrphanPanel && (
          <OrphanPanel
            orphans={orphanNodes}
            onFocusOrphan={handleFocusOrphan}
            onCreateLink={handleCreateLink}
            onAddTag={handleAddTag}
            onClose={() => setShowOrphanPanel(false)}
          />
        )}
      </div>
    </div>
  );
}

